# AI insurance coverage analyser

from dataclasses import dataclass
from typing import Literal

@dataclass
class InsurancePolicy:
    policy_type: str
    insurer: str
    limit_gbp: float
    deductible_gbp: float
    ai_explicitly_covered: bool
    autonomous_decision_excluded: bool
    professional_liability_excluded: bool
    ai_endorsement_in_place: bool
    annual_premium_gbp: float
    renewal_date: str

    def effective_ai_limit(self) -> float:
        """Conservative effective limit accounting for exclusion risk."""
        if not self.ai_explicitly_covered and not self.ai_endorsement_in_place:
            return 0.0   # coverage disputed; treat as zero for planning
        if self.autonomous_decision_excluded and not self.ai_endorsement_in_place:
            return self.limit_gbp * 0.3  # partial coverage assumed
        return self.limit_gbp - self.deductible_gbp

@dataclass
class AiRiskTransferAssessment:
    deployment: str
    expected_annual_loss_gbp: float
    tail_loss_1in100_gbp: float
    vendor_indemnity_gbp: float
    customer_cap_gbp: float     # cap on downstream customer claims
    policies: list[InsurancePolicy]

    def total_effective_coverage_gbp(self) -> float:
        insurance = sum(p.effective_ai_limit() for p in self.policies)
        return self.vendor_indemnity_gbp + insurance

    def retained_risk_gbp(self) -> float:
        return max(0, self.tail_loss_1in100_gbp - self.total_effective_coverage_gbp())

    def coverage_adequacy(self) -> str:
        retained = self.retained_risk_gbp()
        if retained == 0:
            return "adequate"
        elif retained < self.expected_annual_loss_gbp:
            return "borderline"
        else:
            return "inadequate"

    def summary(self) -> dict:
        return {
            "deployment": self.deployment,
            "tail_loss": self.tail_loss_1in100_gbp,
            "total_coverage": round(self.total_effective_coverage_gbp()),
            "retained_risk": round(self.retained_risk_gbp()),
            "adequacy": self.coverage_adequacy(),
        }
